e_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:47:\"WordPress Planet - http://planet.wordpress.org/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"item\";a:50:{i:0;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:89:\"Gutenberg Times: WordPress 7.0 on May 20, Gutenberg 23.0 and more — Weekend Edition 364\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://gutenbergtimes.com/?p=45372\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:86:\"https://gutenbergtimes.com/wordpress-7-0-on-may-20-gutenberg-23-0-weekend-edition-364/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:29525:\"<p class=\"wp-block-paragraph\">Hi there, </p>\n\n\n\n<p class=\"wp-block-paragraph\">Good news, dear friends. WordPress 7.0 has a new release date! May 20, 2026. Announced on Friday, the post featured the <a href=\"https://make.wordpress.org/core/2026/04/22/wordpress-7-0-release-party-updated-schedule/\">updated release party schedule</a>:  All release parties happen in the <a href=\"https://wordpress.slack.com/archives/C02RQBWTW\">Make #core Slack channel</a>. Everyone is welcome to join. </p>\n\n\n\n<p class=\"wp-block-paragraph\">This week, I also traveled to Salzburg, Austria to discuss WordPress 7.0 features with the local community. It was a great joy to meet so many fellow community organizers from WordCamps Vienna, Europe and Kampala, as well as the local meetup organizers and participants from Salzburg. </p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-8f761849 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-embed is-type-rich is-provider-twitter wp-block-embed-twitter\"><div class=\"wp-block-embed__wrapper\">\n<div class=\"embed-twitter\"><blockquote class=\"twitter-tweet\"><p dir=\"ltr\" lang=\"de\">Auf dem Weg nach Salzburg zum WordPress Meetup heute abend <a href=\"https://t.co/vQbGHHN8vv\">https://t.co/vQbGHHN8vv</a><br />Wir werden uns über die Änderungen in WordPress 7.0 unterhalten und die neuen Features vorstellen <a href=\"https://twitter.com/hashtag/WordPress?src=hash&amp;ref_src=twsrc%5Etfw\">#WordPress</a>  Es sind noch Plätze frei! <a href=\"https://t.co/FqgjsaOYjA\">pic.twitter.com/FqgjsaOYjA</a></p>&mdash; Birgit Pauli-Haack (@bph) <a href=\"https://twitter.com/bph/status/2046908121038172547?ref_src=twsrc%5Etfw\">April 22, 2026</a></blockquote></div>\n</div></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-embed is-type-rich is-provider-twitter wp-block-embed-twitter\"><div class=\"wp-block-embed__wrapper\">\n<div class=\"embed-twitter\"><blockquote class=\"twitter-tweet\"><p dir=\"ltr\" lang=\"en\">Such a beautiful privilege to be able to work from the train traveling through the Bavarian landscape. <a href=\"https://twitter.com/hashtag/myofficetoday?src=hash&amp;ref_src=twsrc%5Etfw\">#myofficetoday</a> <a href=\"https://t.co/FdV5A6SaaR\">pic.twitter.com/FdV5A6SaaR</a></p>&mdash; Birgit Pauli-Haack (@bph) <a href=\"https://twitter.com/bph/status/2047243496919093747?ref_src=twsrc%5Etfw\">April 23, 2026</a></blockquote></div>\n</div></figure>\n</div>\n</div>\n</div>\n\n\n<p class=\"wp-block-paragraph\">Enjoy the hopefully restful weekend. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Yours, <img alt=\"💕\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f495.png\" style=\"height: 1em;\" /><br /><em>Birgit</em></p>\n\n\n\n\n\n<h2 class=\"wp-block-heading\" id=\"0-word-press-release-information\">Developing Gutenberg and WordPress</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Ray Morey</strong>, The Repository has the skinny about <a href=\"https://www.therepository.email/wordpress-7-0-gets-a-new-may-20-release-date\"><strong>WordPress 7.0 Gets a New May 20 Release Date</strong></a></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Jonathan Desrosiers</strong> and <strong>Max Schmeling</strong> of the WordPress Core team has published <a href=\"https://github.com/WordPress/distributed-rtc-performance-testing\"><strong>Distributed RTC performance testing</strong></a>, a bash/PHP load-testing tool for the real-time collaboration HTTP polling endpoint coming in WordPress 7.0. Hosting providers can run scenarios — baseline, single idle, sustained polling, burst concurrency, and two-client editing — then submit results directly to WordPress.org. Only curl and bash are required, with WP-CLI optional. If you&#8217;re a host and need reporting credentials, ping Jonathan Desrosiers (<code>@desrosj)</code> or Amy Kamala (<code>@amykamala</code>) in the <a href=\"https://wordpress.slack.com/archives/C3D6T7F8Q\">#hosting Slack channel</a>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>JuanMa Garrido</strong> introduces the <a href=\"https://make.wordpress.org/core/2026/04/16/wordpress-core-dev-environment-toolkit-a-faster-path-to-your-first-core-contribution/\"><strong>WordPress Core Dev Environment Toolkit</strong></a>, a desktop app for macOS, Windows, and Linux that eliminates the painful setup that burns through Contributor Days before anyone writes a line of code. Powered by WordPress Playground, it bundles Git, Node, and npm as JS/WASM — so you install the app, click a button, and you&#8217;re cloning <code>wordpress-develop</code>, running a dev server, and generating Trac patches without touching a terminal. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">The latest Dev note arrival  brings you <a href=\"https://make.wordpress.org/core/2026/04/22/roster-of-design-tools-per-block-wordpress-7-0/\"><strong>Roster of design tools per block (WordPress 7.0 edition</strong>)</a>. I updated a previous version for WordPress 7.0, summarizing design support changes across the last ten releases. WordPress 7.0 adds seven new blocks — Accordion, Breadcrumbs, Icon, Math, Post Time to Read, and the Term Query family — and renames Verse to Poetry. I also removed the Pattern Overrides/Block Bindings column, since both features are now opt-in per block and attribute, making a single checkbox no longer meaningful. </p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://make.wordpress.org/core/2026/04/22/roster-of-design-tools-per-block-wordpress-7-0/\"><img alt=\"screenshot: Roster of design tools per block. \" class=\"wp-image-45433\" height=\"427\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2026/04/Screenshot-2026-04-25-at-13.53.03.png?resize=652%2C427&#038;ssl=1\" width=\"652\" /></a></figure>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong><a href=\"https://make.wordpress.org/core/2026/04/22/whats-new-in-gutenberg-23-0-22-april/\">Gutenberg 23.0</a> </strong>ships a revisions panel for templates, template parts, and patterns (experimental), and completes the Site Editor&#8217;s Design › Identity panel with Site Title and Tagline fields alongside the existing Logo and Icon. Real-time collaboration gets legacy meta box compatibility via a new opt-in flag, plus reliability fixes for concurrent edits and corrupted sync updates. 174 PRs merged, with 8 first-time contributors.</p>\n\n\n\n<p class=\"wp-block-paragraph\">For the Gutenberg Changelog episode 130, <strong>Tammie Lister</strong> and I chatted about AI in Art and WordPress, WordPress 7.0 and Real-tine collaboration and Gutenberg plugin release 22.9 and 23.0. The episode will drop in your favorite podcast episode over the weekend. I hope you listen in and enjoy our conversation. </p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"Tammie Lister and Birgit Pauli-Haack recording Gutenberg Changelog 130\" class=\"wp-image-45452\" height=\"185\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2026/04/Screenshot-2026-04-25-at-15.01.45.png?resize=652%2C185&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<div class=\"wp-block-group has-light-background-background-color has-background\"><div class=\"wp-block-group__inner-container is-layout-constrained wp-block-group-is-layout-constrained\">\n<p class=\"wp-block-paragraph\"><img alt=\"🎙\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f399.png\" style=\"height: 1em;\" /> The latest episode is <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-129/\">Gutenberg Changelog #129 Artificial Intelligence, WordPress 7.0 and Gutenberg 22.8</a> with Beth Soderberg, of BeThink Studio </p>\n\n\n\n<figure class=\"wp-block-image size-full is-style-no-vertical-margin\"><img alt=\"Beth Soderberg and Birgit Pauli-Haack recording the Gutenberg Changelog 129\" class=\"wp-image-45032\" height=\"185\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2026/03/Screenshot-2026-03-28-at-12.00.17.png?resize=652%2C185&#038;ssl=1\" width=\"652\" /></figure>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-rich is-provider-pocket-casts wp-block-embed-pocket-casts\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div></div></div>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"0-p\">Plugins, Themes, and Tools for #nocode site builders and owners</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Brian Coords</strong>, developer advocate at WooCommerce, walks you through<strong> <a href=\"https://www.youtube.com/watch?v=SJLDjECyjI8\">a prototype plugin called WP Content Types</a></strong>, a block-native take on custom post types and fields built directly into the WordPress interface using Data Views and Data Forms. You&#8217;ll see AI generate a Recipe content type, configure fields with core components, connect templates through block bindings, and explore a &#8220;Fields Only&#8221; modern UI. It&#8217;s a V1 vision for content modeling that leaves legacy backwards compatibility behind. </p>\n\n\n\n<p class=\"wp-block-paragraph\"><br />Coords implementation goes much further than  a similar project &#8220;Create Content Model&#8221; Autumn Fjeld and Candy Tsai demo&#8217;d at WordCamp Asia 2025 in Manila, Philippines. Their repo is <a href=\"https://github.com/Automattic/create-content-model\">available on GitHub</a> including links to the talk and demo video. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">In his latest video, <strong>Wes Theron</strong> walks you through <a href=\"https://www.youtube.com/watch?v=umdJSDqEDpU\"><strong>using block dimensions to control layout in WordPress</strong></a> — without touching any CSS. You&#8217;ll learn how to find the dimensions panel in the editor and learn when to reach for padding (space inside a block), margin (space around it), block spacing (gaps between child blocks), and minimum height. Each setting gets a practical demo so you can confidently build cleaner, more polished pages with better visual hierarchy.</p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Alex de Borba</strong> makes a pointed case in <a href=\"https://www.atmostfear-entertainment.com/blogs/wpcoven/why-developers-keep-reaching-for-builders-over-block-themes/\"><strong>Why Developers Keep Reaching for Builders Over Block Themes</strong></a> that the &#8220;block themes can&#8217;t compete&#8221; narrative is more habit than fact. With <code>theme.json</code> v3, <code>register_block_style()</code>, synced patterns, and <code>wp_enqueue_block_style()</code>, you can build design systems, reusable components, and performant layouts without proprietary tools — and without locking your clients into someone else&#8217;s ecosystem when developer relationships change.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">At WordCamp Asia, the <a href=\"https://wordpress.tv/2026/04/21/wordpress-speed-build-challenge-2/\"><strong>WordPress Speed Build Challenge</strong></a> returned for a second round: experienced builders had 30 minutes, a surprise brief revealed live on stage, and nothing but the Full Site Editor — no page builders, no custom code. Watch how they tackle layout, content, styling, and real-time problem-solving under pressure while narrating their decisions. A fun, unscripted window into smart site editor workflows for anyone curious about block-based building. The recording is now available on WordPressTV.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"upcoming-events\">Upcoming Events</h3>\n\n\n\n<p class=\"wp-block-paragraph\">The <a href=\"https://atarim.io/summit/\">6th annual <strong>Web Agency Summit</strong></a> runs April 27–30, 2026. It&#8217;s free, virtual, and built for agency owners ready to stop winging it. Hosted by <strong>Vito Peleg</strong>, <strong>Stephanie Hudson</strong>, and <strong>Andrew Palmer</strong>, four days of live expert sessions cover the full agency arc: Build, Expand, Scale, and Thrive. Speakers include Eugene Levin from Semrush and Karim Marucchi of Crowd Favorite. Think of it as a week-long podcast you keep open while you work.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;re in New York on April 29, <a href=\"https://automattic.com/2026/04/hilary-mason/\"><strong>dev/ai/nyc with Hilary Mason</strong></a> is worth your evening. Hilary Mason — CEO of Hidden Door, founder of Fast Forward Labs, and former Chief Scientist at bit.ly — joins Jesse Friedman, who leads WP Cloud at Automattic, for a fireside chat on AI, creativity, and human-computer interaction. Doors open at 5:30 PM at Automattic&#8217;s NoHo space on Crosby Street, with drinks and bites after. <a href=\"https://luma.com/jae3jufw\">Registration is on Luma</a>. The event is free of charge. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">The <a href=\"https://checkoutsummit.com/\"><strong>Checkout Summit</strong></a> in-person event just wrapped up in Palermo, Sicily — don&#8217;t be sad you missed the arancine and Aperol Spritz. Organizer <strong>Rodolfo Melogli</strong> of Business Bloomer will reassemble 18+ speakers for the online edition, <strong>{Reloaded}</strong>, on May 7–8, 2026 starting at just €20. The WooCommerce-focused lineup covers SEO after AI, MCP integrations, hosting security, Shopify comparisons, and scaling strategies — practical sessions, zero fluff, built for developers and agency pros.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Rae Morey</strong>, The Repository has the skinny for you in <a href=\"https://www.therepository.email/cant-make-it-to-palermo-checkout-summit-is-going-online-in-may\"><strong>Can’t Make It to Palermo? Checkout Summit Is Going Online in May</strong></a>. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">Uganda&#8217;s biggest annual student web design competition, <a href=\"https://events.wordpress.org/uganda/2026/competition/\"><strong>Website Projects Competition 2026</strong></a>, takes place on J<strong>une 9, 2026</strong> at Busoga College, Mwiri. Under the theme &#8220;Fueling Innovation Through WordPress,&#8221; 20 student teams across three age categories — Cubs (12 &amp; under), Rising Stars (13–18), and Explorers (18+) — compete by building and pitching WordPress websites to a live audience of 200+. Sponsored by Automattic and Woo. Registration and sponsorship are open.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wpaccessibility.day/2026/sponsorship/\"><strong>WordPress Accessibility Day 2026</strong></a> is a free, 24-hour global livestream on <strong>October 7–8, 2026</strong>, dedicated to accessibility best practices for WordPress developers, designers, and content creators. The volunteer-led nonprofit event includes live captions and ASL interpretation for all sessions, with corrected transcripts published afterward. It&#8217;s pre-approved for IAAP continuing education credits. <a href=\"https://wpaccessibility.day/2026/sponsorship/\">Sponsorships are now open,</a> ranging from $150 Microsponsors to $5,000 Platinum packages.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Gina Lucia</strong>, freelance writer, published a beginner-friendly walkthrough on <strong><a href=\"https://olliewp.com/wordpress-block-patterns/\">what WordPress block patterns are and how to use them</a> </strong>for OllieWP. You&#8217;ll learn how patterns differ from synced patterns, templates, and template parts, why block themes unlock their full potential for headers, footers, and full-page layouts, and how to browse, preview, insert, and customize curated patterns in Ollie&#8217;s pattern library. A handy primer if you&#8217;re moving from classic themes into the full site editing experience.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Nathan Wrigley</strong> sits down with <a href=\"https://wpbuilds.com/2026/04/16/464-why-brian-gardner-is-betting-big-on-block-themes/\"><strong>Brian Gardner </strong>to talk block themes, AI, and the future of WordPress design</a>. The Genesis co-creator argues that many developers are still judging the block editor by a five-year-old experience — and missing how far it&#8217;s come. He shares his work on <a href=\"https://powder.design\">Powder</a>, explores how tools like Ollie and Miles are bridging AI-generated design with native WordPress blocks, and asks the question keeping him up at night: do we still need hundreds of themes, or is one solid base theme plus vertical-specific patterns actually the future?</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>JC Palmes,</strong> WebDev Studios and regular guest on the Gutenberg Changelog, makes the case that <a href=\"https://wordpress.tv/2026/04/21/from-chaos-to-clarity-scaling-teams-with-block-theme-standards/\">block themes can replace one-off chaos with repeatable consistency</a> on large team projects. The approach: start with a shared starter theme, build a reusable pattern library, and centralize design decisions in <code>theme.json</code>. She also tackles the less glamorous side — onboarding developers, running QA, and finding the right balance between editorial freedom and long-term maintainability. Practical and team-focused, it&#8217;s a playbook worth your time if you&#8217;re managing multi-site or multi-developer WordPress work.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Anne Katzeff</strong> walks you through <strong><a href=\"https://www.askdesign.biz/blog/2026/04/exploring-the-wordpress-cover-block-hero-section/\">using the Cover block as a Hero section</a> </strong>with a Call to Action. Starting from default settings, she shows how alignment (wide or full width), overlay color and opacity, minimum height, focal point, and inner block layout work together to create a polished hero. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Katzeff also created a <a href=\"https://www.youtube.com/watch?v=fSy7ZM7woG4\">companion video tutorial</a> to follow along with how she manipulates the cover block for her purposes. All very practical and beginner-friendly.</p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n<div class=\"ng-block-eb8d4ec9e53d9b3a wp-block-newsletterglue-container ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div class=\"ng-block-vs ng-block-vs-1\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div><div><div class=\"ng-block-hs ng-block-hs-1\" height=\"0\" style=\"width: 0px;\"></div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 20px; padding-bottom: 20px; padding-left: 0px; padding-right: 0px; text-align: none; color: #666666; background-color: #fdfcea; border-radius: 12px;\"><div class=\"ng-block-f3ed9266ee45f673 wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p><strong> <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/\" rel=\"noreferrer noopener\" target=\"_blank\">&#8220;Keeping up with Gutenberg &#8211; Index 2025&#8221;</a> </strong><br />A chronological list of the WordPress Make Blog posts from various teams involved in Gutenberg development: Design, Theme Review Team, Core Editor, Core JS, Core CSS, Test, and Meta team from Jan. 2024 on. Updated by yours truly. </p></div></div></div></div>\n\n<div class=\"ng-block-a42465dd237fc04d wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p>The previous years are also available: <br /><strong><strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2020/\">2020</a> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2021/\">2021</a></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2022/\">2022</a></strong></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2023\">2023</a></strong> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2024/\"><strong>2024</strong></a></p></div></div></div></div></div><div class=\"ng-block-hs ng-block-hs-2\" height=\"0\" style=\"width: 0px;\"></div></div><div><div class=\"ng-block-vs ng-block-vs-2\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div></div></div>\n\n\n<h2 class=\"wp-block-heading\" id=\"ai-in-wordpress\">AI in WordPress</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Automattic&#8217;s head of global expansion <strong>James Grierson</strong> argues in <a href=\"https://automattic.com/2026/04/21/wordpress-operating-system-agentic-web/\"><strong>WordPress: The Operating System of the Agentic Web</strong></a> that WordPress&#8217;s open-source transparency, 90,000+ plugin ecosystem, REST API, and MCP support make it the ideal foundation for AI agents. WordPress.com&#8217;s full MCP write capabilities — launched in March 2026—let agents create and manage content via natural conversation. Challenges remain around legacy code, inconsistent plugin quality, and PHP perception, but Grierson sees AI itself as the solution to those very problems.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">Inspired by a trip to WordCamp Asia 2026 in Mumbai, <strong>Chandra Patel</strong> built the <a href=\"https://chandra.dev/wp-rest-api-playground/\">WordPress REST API Playground</a> — a free plugin developed entirely with Claude Code in just 2–3 hours. The three-panel interface lets you browse all registered REST API routes, build requests with schema-driven form fields, and view syntax-highlighted responses with timing info. A handy Code tab generates ready-to-use JavaScript, PHP, and cURL snippets for every request. Available on <a href=\"https://github.com/chandrapatel/wp-rest-api-playground\">GitHub</a>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Pablo Postigo</strong> used <a href=\"https://pablopostigo.com/thoughts/using-studio-code-to-travel-back-in-time/\">Studio Code</a>, Automattic&#8217;s new AI coding agent for building WordPress sites locally, to finally redesign <a href=\"https://govoid.es/\">Govoid.es</a>, a geek news blog he co-founded in 2009 that&#8217;s been dormant since 2013. He used Claude to craft a detailed design brief, fed it to Studio Code (running Claude Opus 4.7), and got a complete minimalist dark-mode block theme generated in one shot, with only a couple of hours of refinement before pushing straight to production. <em><a href=\"https://www.npmjs.com/package/wp-studio\">Studio Code</a> is still in alpha, there will be dragons <img alt=\"🐲\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f432.png\" style=\"height: 1em;\" /></em></p>\n\n\n<div class=\"ng-block-20583fafc02d177a wp-block-newsletterglue-container ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div class=\"ng-block-vs ng-block-vs-1\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div><div><div class=\"ng-block-hs ng-block-hs-1\" height=\"0\" style=\"width: 0px;\"></div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 20px; padding-bottom: 20px; padding-left: 0px; padding-right: 0px; text-align: none; color: #666666; background-color: #f8f8f8; border-radius: 8px;\"><div class=\"ng-block-7a2a32b4d0cc7d6f wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p><strong><a href=\"https://gutenbergtimes.com/need-a-zip-from-master/\">Need a plugin .zip from Gutenberg&#8217;s master branch?</a></strong><br />Gutenberg Times provides daily build for testing and review.</p></div></div></div></div>\n\n<div class=\"ng-block-dff12a1348d30af5 wp-block-newsletterglue-image ng-block size-full is-resized\" width=\"100%\"><div><div><div align=\"center\" class=\"ng-block-td\" style=\"padding-top: 0px; padding-bottom: 0px; padding-left: 0px; padding-right: 0px;\"><a href=\"https://playground.wordpress.net/?blueprint-url=https://gutenbergtimes.com/wp-content/uploads/2020/11/playnightly.json\"><img alt=\"\" class=\"wp-image-42874 ng-image\" height=\"45\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2024/02/Screenshot-2025-11-15-at-12.06.44.png?resize=196%2C45&#038;ssl=1\" style=\"border-style: none; border-color: transparent;\" width=\"196\" /></a></div></div></div></div>\n\n<div class=\"ng-block-431caaafee805725 wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p>Now also available via <a href=\"https://playground.wordpress.net/?blueprint-url=https://gutenbergtimes.com/wp-content/uploads/2020/11/playnightly.json\">WordPress Playground</a>. There is no need for a test site locally or on a server. Have you been using it? <a href=\"mailto:pauli@gutenbergtimes.com\">Email me </a>with your experience.</p></div></div></div></div></div><div class=\"ng-block-hs ng-block-hs-2\" height=\"0\" style=\"width: 0px;\"></div></div><div><div class=\"ng-block-vs ng-block-vs-2\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div></div></div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"has-text-align-center has-small-font-size wp-block-paragraph\"><em>Questions? Suggestions? Ideas? </em><br /><em>Don&#8217;t hesitate to send <a href=\"mailto:pauli@gutenbergtimes.com\">them via email</a> or</em><br /><em> send me a message on WordPress Slack or Twitter @bph</em>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"has-text-align-center has-small-font-size wp-block-paragraph\">For questions to be answered on the <a href=\"http://gutenbergtimes.com/podcast\">Gutenberg Changelog</a>, <br />send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a></p>\n\n\n<div class=\"ng-block-2acfc57256f30911 wp-block-newsletterglue-separator ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"center\" class=\"ng-block-td\" style=\"padding-top: 20px; padding-bottom: 20px; padding-left: 20px; padding-right: 20px; color: #666666;\"><hr style=\"background-color: transparent; color: transparent; margin: 0; border: 0; border-top: 1px solid #666666; width: 560px; height: 0;\" /></div></div></div></div>\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\"><div class=\"ng-block-0ee7b0d8ecc95da4 wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 14px; font-family: Helvetica; line-height: 0.2; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p><strong>Featured Image: </strong></p></div></div></div></div></div>\n\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 25 Apr 2026 13:08:16 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"Greg Ziółkowski: WordPress Core AI — 7.1 Planning and Beyond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:26:\"https://gziolo.pl/?p=14672\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"https://gziolo.pl/2026/04/25/wordpress-core-ai-7-1-planning-and-beyond/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:381:\"Building on the Abilities API and three read-only core abilities (core/get-site-info, core/get-user-info, core/get-environment-info) shipped in 6.9, WordPress 7.0 brings the server-side WP AI Client. Together these form the baseline: a way to declare what WordPress can do, and a way to connect to providers that reason about it. This post outlines what I&#8217;d like to [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 24 Apr 2026 22:13:04 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:17:\"Greg Ziółkowski\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"Akismet: Akismet v5.7: ready for Abilities and Connectors\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://akismet.com/?p=284737\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"https://akismet.com/blog/akismet-v5-7-ready-for-abilities-and-connectors/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1762:\"<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/plugins/akismet/\">Akismet WordPress plugin</a> v5.7 is out today. This release focuses on fitting more neatly into where WordPress is heading next.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"abilities-api-support\">Abilities API support</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Akismet now supports the <a href=\"https://developer.wordpress.org/news/2025/11/introducing-the-wordpress-abilities-api/\">Abilities API</a>, giving WordPress a clear, structured way to understand what Akismet can do, like checking content for spam or retrieving stats.</p>\n\n\n\n<p class=\"wp-block-paragraph\">It’s a subtle change, but it makes integrations more predictable and easier to build on top of.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"connectors-for-wordpress-7-0\">Connectors (for WordPress 7.0)</h3>\n\n\n\n<p class=\"wp-block-paragraph\">We’ve also added early support for WordPress Connectors, which is landing in WordPress 7.0.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Connectors provide a consistent way to manage API keys and external services across plugins. With Akismet ready for this, your API key setup will slot into a more unified experience as sites upgrade.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"plus-the-usual-polish\">Plus the usual polish</h3>\n\n\n\n<p class=\"wp-block-paragraph\">A handful of fixes and improvements round things out to keep things running smoothly.</p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\n\n\n<p class=\"wp-block-paragraph\">To upgrade, visit the Updates page of your WordPress dashboard and follow the instructions. If you need to download the plugin zip file directly, links to all versions are available in <a href=\"http://wordpress.org/plugins/akismet/\">the WordPress plugins directory</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 24 Apr 2026 01:56:59 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:17:\"Chris Rosser 🏔\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:86:\"Open Channels FM: Live at CloudFest: Ecommerce With New Caching for Better Conversions\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2553109\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:93:\"https://openchannels.fm/the-future-of-fast-ecommerce-with-new-caching-for-better-conversions/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:196:\"Site speed is crucial for e-commerce success; delays lead to cart abandonment, especially on mobile. Experts discuss caching solutions and user experience improvements to enhance conversion rates.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 23 Apr 2026 13:33:51 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"Open Channels FM: The Philosophy Behind Sustaining Independent Voices\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2552898\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"https://openchannels.fm/the-philosophy-behind-sustaining-independent-voices/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:197:\"The \"Keep It Open\" initiative emphasizes sustainability and independence in the open web community, inviting contributors to support honest conversations without focusing on rewards or exclusivity.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 23 Apr 2026 11:02:32 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:46:\"Gutenberg Times: WordPress 7.0 Source of Truth\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://gutenbergtimes.com/?p=44884\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://gutenbergtimes.com/wordpress-7-0-source-of-truth/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:82138:\"<p class=\"wp-block-paragraph\" id=\"welcome-to-the-source-of-truth-for-wordpress-6-9\">Welcome to the Source of Truth for WordPress 7.0!</p>\n\n\n\n<p class=\"wp-block-paragraph\">Before you dive headfirst into all the big and small changes and pick your favorites, make sure to read these preliminary thoughts about this post and how to use it. If you have questions, leave a comment or email me at <a href=\"mailto:pauli@gutenbergtimes.com\">pauli@gutenbergtimes.com</a>. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Huge Thank You to all collaborators on this post: Anne McCarthy, Sarah Norris, Ella van Durpe, Maggie Cabrera, Ben Dwyer, Jonathan Bossenger, Justin Tadlock, Dave Smith, Courtney Robertson and a lot more. It&#8217;s takes a village&#8230;</p>\n\n\n\n<div class=\"wp-block-group has-primary-color has-text-color has-link-color has-small-font-size wp-elements-a8bb9ec1783f5f0c5623981a664fedce is-content-justification-left is-nowrap is-layout-flex wp-container-core-group-is-layout-fbe4aca3 wp-block-group-is-layout-flex\" style=\"text-decoration: none;\">\n<p class=\"wp-block-paragraph\">Estimated reading time</p>\n\n\n<div class=\"wp-block-post-time-to-read\">21–31 minutes</div>\n\n\n<p class=\"wp-block-paragraph\">at </p>\n\n\n<div class=\"wp-block-post-time-to-read\">4,911 words</div></div>\n\n\n\n<div class=\"wp-block-group has-light-background-background-color has-background\"><div class=\"wp-block-group__inner-container is-layout-constrained wp-block-group-is-layout-constrained\">\n<p class=\"wp-block-paragraph\"><strong>Table of Contents</strong></p>\n\n\n\n<nav class=\"wp-block-table-of-contents\"><ol><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-7-0-source-of-truth/#changelog\">Changelog</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-7-0-source-of-truth/#important-note-guidelines\">Important note/guidelines</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-7-0-source-of-truth/#overview\">Overview </a><ol><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-7-0-source-of-truth/#important-links\">Important links:</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-7-0-source-of-truth/#assets\">Assets </a></li></ol></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-7-0-source-of-truth/#tags\">Tags</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-7-0-source-of-truth/#priority-items-for-wordpress-7-0\">Priority items for WordPress 7.0 </a><ol><li><a class=\"wp-block