:\"field_bn2_g\",\"banner_2_renk\":\"\",\"_banner_2_renk\":\"field_bn2_r\",\"banner_3_baslik\":\"\",\"_banner_3_baslik\":\"field_bn3_b\",\"banner_3_alt_baslik\":\"\",\"_banner_3_alt_baslik\":\"field_bn3_ab\",\"banner_3_link\":\"\",\"_banner_3_link\":\"field_bn3_l\",\"banner_3_gorsel\":\"\",\"_banner_3_gorsel\":\"field_bn3_g\",\"banner_3_renk\":\"\",\"_banner_3_renk\":\"field_bn3_r\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/press-kit {\"name\":\"acf/press-kit\",\"data\":{\"baslik\":\"\",\"_baslik\":\"field_pk_baslik\",\"aciklama\":\"\",\"_aciklama\":\"field_pk_aciklama\",\"dosya_1_metin\":\"\",\"_dosya_1_metin\":\"field_pk_d1m\",\"dosya_1_link\":\"\",\"_dosya_1_link\":\"field_pk_d1l\",\"dosya_2_metin\":\"\",\"_dosya_2_metin\":\"field_pk_d2m\",\"dosya_2_link\":\"\",\"_dosya_2_link\":\"field_pk_d2l\",\"pdf_url\":\"\",\"_pdf_url\":\"field_pk_pdf\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/news {\"name\":\"acf/news\",\"data\":{\"baslik\":\"\",\"_baslik\":\"field_nw_baslik\",\"tum_haberler_metni\":\"\",\"_tum_haberler_metni\":\"field_nw_tum\",\"tum_haberler_linki\":\"\",\"_tum_haberler_linki\":\"field_nw_tum_link\",\"haber_kategorisi\":\"\",\"_haber_kategorisi\":\"field_nw_kat\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/program {\"name\":\"acf/program\",\"data\":{\"baslik\":\"\",\"_baslik\":\"field_pg_baslik\",\"aciklama\":\"\",\"_aciklama\":\"field_pg_aciklama\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/quick-links {\"name\":\"acf/quick-links\",\"data\":{\"baslik\":\"\",\"_baslik\":\"field_ql_b\",\"aciklama\":\"\",\"_aciklama\":\"field_ql_a\",\"kurumsal_baslik\":\"\",\"_kurumsal_baslik\":\"field_ql_kb\",\"bulten_baslik\":\"\",\"_bulten_baslik\":\"field_ql_bb\",\"bulten_aciklama\":\"\",\"_bulten_aciklama\":\"field_ql_ba\",\"sosyal_medya\":\"\",\"_sosyal_medya\":\"field_ql_sosyal\",\"kurumsal_linkler\":\"\",\"_kurumsal_linkler\":\"field_ql_kurumsal\"},\"mode\":\"edit\",\"metadata\":{\"blockVisibility\":false}} /-->','Anasayfa','','inherit','closed','closed','','100-revision-v1','','','2026-04-26 01:54:01','2026-04-25 22:54:01','',100,'http://localhost:9090/?p=983',0,'revision','',0),(984,1,'2026-04-26 01:57:59','2026-04-25 22:57:59','<!-- wp:acf/biz-kimiz {\"name\":\"acf/biz-kimiz\",\"data\":{\"baslik\":\"Hakkımızda\",\"_baslik\":\"field_bk_baslik\",\"metin\":\"\\u003cp class=\\u0022preFade fadeIn\\u0022\\u003eUluslararası İşçi Filmleri Festivali, her yıl 1-8 Mayıs tarihlerinde İstanbul, Ankara ve İzmir’de eş zamanlı gerçekleşen ve sonrasında da yıl sonuna kadar Türkiye\'nin bir çok şehrinde farklı zamanlarda izleyici ile buluşan bir film festivalidir.\\u003c/p\\u003e\\r\\n\\u003cp class=\\u0022preFade fadeIn\\u0022\\u003e\\u003cstrong\\u003e\\u003cem\\u003eSponsorsuz, Yarışmasız, Ücretsiz ve Alternatif Festival!\\u003c/em\\u003e\\u003c/strong\\u003e\\u003c/p\\u003e\\r\\n\\u003cp class=\\u0022preFade fadeIn\\u0022\\u003e2006 yılında “Üretin Gösterelim!” dedik ve yıllardır, dünyadaki İşçi Filmleri Festivallerinin ortak ağıyla ürettiklerinizi gösteriyoruz. Ana akım sinema solanları tekeline karşı, alternatif ücretsiz gösterimler yapmaya ve ana akım sinema salonlarında yer bulamamış filmleri izleyici ile buluşturmaya devam ediyoruz.\\u003c/p\\u003e\\r\\n\\u003cp class=\\u0022sqsrte-small preFade fadeIn\\u0022\\u003e\\u003cstrong\\u003e\\u003cem\\u003eGönüllü Emeğin Festivali​\\u003c/em\\u003e\\u003c/strong\\u003e\\u003c/p\\u003e\\r\\n\\u003cp class=\\u0022preFade fadeIn\\u0022\\u003eİşçi Filmleri Festivali için çalışan, emek veren herkes gönüllüdür. Festivalin düzenlendiği her ilde bu gönüllülerden oluşan bir festival komitesi vardır. Festival komiteleri, sinemayı seven, sinemanın bir farkındalık ve toplumsal hafıza aracı olduğunu düşünen insanlardan oluşur.\\u003c/p\\u003e\\r\\n\\u003cp class=\\u0022preFade fadeIn\\u0022\\u003eBu komitelerden birinde yer almak için İşçi Filmleri Festivali’nin gönüllüsü olmak yeterlidir.\\u003c/p\\u003e\",\"_metin\":\"field_bk_metin\",\"tasarim_stili\":\"beyaz\",\"_tasarim_stili\":\"field_bk_tasarim\",\"ozel_renk_aktif\":\"0\",\"_ozel_renk_aktif\":\"field_bk_ozel_renk_aktif\"},\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/biz-kimiz {\"name\":\"acf/biz-kimiz\",\"data\":{\"baslik\":\" NEDEN İŞÇİ FİLMLERİ FESTİVALİ? \",\"_baslik\":\"field_bk_baslik\",\"metin\":\"\\u003cp class=\\u0022preFade fadeIn\\u0022\\u003eİnsanlık tarihi yerleşik hayata geçtiği andan itibaren kendi bünyesinde sınıfsal, cinsel, etnik çelişkiler üreterek bugüne kadar geldi. Tarihin belli dönemlerinde etnik, dinsel, ulusal çelişkiler şeklinde görünen ve bu temelde şekillenen savaşlarla bu sorunlar çözülmeye çalışılmışken bazı tarihsel aktörler de bu sorunların çözümünde etnik, dinsel, kültürel çatışmaların dışına çıkarak eşitlikçi, özgürlükçü çözümler önermiş ve bunların mücadelesini vermiştir. Bu çabalar bazen entelektüel / vicdani ütopyalarla sınırlı kalırken bazen kendiliğinden isyanlarla dile getirilmeye çalışılmıştır.​\\u003c/p\\u003e\\r\\n\\u003cp class=\\u0022preFade fadeIn\\u0022\\u003eTarihte ilk kez işçi sınıfı mücadelesi ve bu mücadelede fikri olarak olgunlaşan sosyalizm, dünya çapında sınıfsız, sömürüsüz, devletsiz bir hayat özlemini “bilimsel” temellere oturtmuş ve gerçekleşebilir bir düşünce haline getirmiştir.​\\u003c/p\\u003e\\r\\n\\u003cp class=\\u0022preFade fadeIn\\u0022\\u003eBu fikrin ışığında Paris Komünü deneyimi ve ardından tarihte ilk kez sınıf egemenliğine son verilen bir sosyal düzenin kurulduğu Bolşevik Rus devrimi gerçekleşmiş ve dünyaya bunun mümkün olabileceğini göstermiştir.\\u003c/p\\u003e\\r\\n\\u003cp class=\\u0022preFade fadeIn\\u0022\\u003e21.yüzyılın gerçekliğinde  bütün toplumsal ilişki ve çelişkilerin yeniden oluştuğu bir süreçte, işçi sınıfının 150 yıllık mücadele sürecinin başarı ve başarısızlıklarının eleştirisinden bağımsız olarak, kapitalizmin ve emperyalizmin dünyanın bütün toplumsal, insani değerlerini çürüttüğü, emekçileri ve yoksul halkların zenginliklerini sömürmekle kalmayıp doğayı bile metalaştırdığı bu yüzyılda  işçi sınıfı mücadelesinin sınıfsız, sömürüsüz, eşitlikçi, adil bir dünya özlemine sahip çıkıyor ve bu mirasın yeni kuşaklara aktarılmasını misyonumuz olarak kabul ediyoruz.\\u003c/p\\u003e\",\"_metin\":\"field_bk_metin\",\"tasarim_stili\":\"koyu\",\"_tasarim_stili\":\"field_bk_tasarim\",\"ozel_renk_aktif\":\"0\",\"_ozel_renk_aktif\":\"field_bk_ozel_renk_aktif\"},\"mode\":\"edit\"} /-->','Hakkımızda','','publish','closed','closed','','hakkimizda','','','2026-04-26 02:16:24','2026-04-25 23:16:24','',0,'http://localhost:9090/?page_id=984',0,'page','',0),(985,1,'2026-04-26 01:57:59','2026-04-25 22:57:59','<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\"><strong>Uluslararası İşçi Filmleri Festivali, her yıl 1-8 Mayıs tarihlerinde İstanbul, Ankara ve İzmir’de eş zamanlı gerçekleşen ve sonrasında da yıl sonuna kadar Türkiye\'nin bir çok şehrinde farklı zamanlarda izleyici ile buluşan bir film festivalidir.</strong> </h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong><em>Sponsorsuz, Yarışmasız, Ücretsiz ve Alternatif Festival!</em></strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>2006 yılında “Üretin Gösterelim!” dedik ve yıllardır, dünyadaki İşçi Filmleri Festivallerinin ortak ağıyla ürettiklerinizi gösteriyoruz. Ana akım sinema solanları tekeline karşı, alternatif ücretsiz gösterimler yapmaya ve ana akım sinema salonlarında yer bulamamış filmleri</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>izleyici ile buluşturmaya devam ediyoruz.</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong><em>Gönüllü Emeğin Festivali​</em></strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>İşçi Filmleri Festivali için çalışan, emek veren herkes gönüllüdür. Festivalin düzenlendiği her ilde bu gönüllülerden oluşan bir festival komitesi vardır. Festival komiteleri, sinemayı seven, sinemanın bir farkındalık ve toplumsal hafıza aracı olduğunu düşünen insanlardan oluşur.</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Bu komitelerden birinde yer almak için İşçi Filmleri Festivali’nin gönüllüsü olmak yeterlidir.</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">NEDEN İŞÇİ FİLMLERİ FESTİVALİ</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>İnsanlık tarihi yerleşik hayata geçtiği andan itibaren kendi bünyesinde sınıfsal, cinsel, etnik çelişkiler üreterek bugüne kadar geldi. Tarihin belli dönemlerinde etnik, dinsel, ulusal çelişkiler şeklinde görünen ve bu temelde şekillenen savaşlarla bu sorunlar çözülmeye çalışılmışken bazı tarihsel aktörler de bu sorunların çözümünde etnik, dinsel, kültürel çatışmaların dışına çıkarak eşitlikçi, özgürlükçü çözümler önermiş ve bunların mücadelesini vermiştir. Bu çabalar bazen entelektüel / vicdani ütopyalarla sınırlı kalırken bazen kendiliğinden isyanlarla dile getirilmeye çalışılmıştır.​</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Tarihte ilk kez işçi sınıfı mücadelesi ve bu mücadelede fikri olarak olgunlaşan sosyalizm, dünya çapında sınıfsız, sömürüsüz, devletsiz bir hayat özlemini “bilimsel” temellere oturtmuş ve gerçekleşebilir bir düşünce haline getirmiştir.​</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Bu fikrin ışığında Paris Komünü deneyimi ve ardından tarihte ilk kez sınıf egemenliğine son verilen bir sosyal düzenin kurulduğu Bolşevik Rus devrimi gerçekleşmiş ve dünyaya bunun mümkün olabileceğini göstermiştir.&nbsp;</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>21.yüzyılın gerçekliğinde &nbsp;bütün toplumsal ilişki ve çelişkilerin yeniden oluştuğu bir süreçte, işçi sınıfının 150 yıllık mücadele sürecinin başarı ve başarısızlıklarının eleştirisinden bağımsız olarak, kapitalizmin ve emperyalizmin dünyanın bütün toplumsal, insani değerlerini çürüttüğü, emekçileri ve yoksul halkların zenginliklerini sömürmekle kalmayıp doğayı bile metalaştırdığı bu yüzyılda &nbsp;işçi sınıfı mücadelesinin sınıfsız, sömürüsüz, eşitlikçi, adil bir dünya özlemine sahip çıkıyor ve bu mirasın yeni kuşaklara aktarılmasını misyonumuz olarak kabul ediyoruz.</strong>&nbsp;</p>\n<!-- /wp:paragraph -->','Hakkımızda','','inherit','closed','closed','','984-revision-v1','','','2026-04-26 01:57:59','2026-04-25 22:57:59','',984,'http://localhost:9090/?p=985',0,'revision','',0),(986,1,'2026-04-26 01:59:22','2026-04-25 22:59:22','<!-- wp:acf/biz-kimiz {\"name\":\"acf/biz-kimiz\",\"data\":{\"baslik\":\"Hakkımızda\",\"_baslik\":\"field_bk_baslik\",\"metin\":\"Uluslararası İşçi Filmleri Festivali, her yıl 1-8 Mayıs tarihlerinde İstanbul, Ankara ve İzmir’de eş zamanlı gerçekleşen ve sonrasında da yıl sonuna kadar Türkiye\'nin bir çok şehrinde farklı zamanlarda izleyici ile buluşan bir film festivalidir. \\r\\n\\r\\nSponsorsuz, Yarışmasız, Ücretsiz ve Alternatif Festival!\\r\\n\\r\\n2006 yılında “Üretin Gösterelim!” dedik ve yıllardır, dünyadaki İşçi Filmleri Festivallerinin ortak ağıyla ürettiklerinizi gösteriyoruz. Ana akım sinema solanları tekeline karşı, alternatif ücretsiz gösterimler yapmaya ve ana akım sinema salonlarında yer bulamamış filmleri\\r\\n\\r\\nizleyici ile buluşturmaya devam ediyoruz.\\r\\n\\r\\nGönüllü Emeğin Festivali​\\r\\n\\r\\nİşçi Filmleri Festivali için çalışan, emek veren herkes gönüllüdür. Festivalin düzenlendiği her ilde bu gönüllülerden oluşan bir festival komitesi vardır. Festival komiteleri, sinemayı seven, sinemanın bir farkındalık ve toplumsal hafıza aracı olduğunu düşünen insanlardan oluşur.\\r\\n\\r\\nBu komitelerden birinde yer almak için İşçi Filmleri Festivali’nin gönüllüsü olmak yeterlidir.\",\"_metin\":\"field_bk_metin\",\"buton_metni\":\"\",\"_buton_metni\":\"field_bk_buton_metni\",\"buton_link\":\"\",\"_buton_link\":\"field_bk_buton_link\",\"gorsel_1\":\"\",\"_gorsel_1\":\"field_bk_gorsel_1\",\"gorsel_2\":\"\",\"_gorsel_2\":\"field_bk_gorsel_2\"},\"mode\":\"edit\"} /-->','Hakkımızda','','inherit','closed','closed','','984-revision-v1','','','2026-04-26 01:59:22','2026-04-25 22:59:22','',984,'http://localhost:9090/?p=986',0,'revision','',0),(987,1,'2026-04-26 01:59:32','2026-04-25 22:59:32','<!-- wp:acf/biz-kimiz {\"name\":\"acf/biz-kimiz\",\"data\":{\"baslik\":\"Hakkımızda1\",\"_baslik\":\"field_bk_baslik\",\"metin\":\"Uluslararası İşçi Filmleri Festivali, her yıl 1-8 Mayıs tarihlerinde İstanbul, Ankara ve İzmir’de eş zamanlı gerçekleşen ve sonrasında da yıl sonuna kadar Türkiye\'nin bir çok şehrinde farklı zamanlarda izleyici ile buluşan bir film festivalidir. \\r\\n\\r\\nSponsorsuz, Yarışmasız, Ücretsiz ve Alternatif Festival!\\r\\n\\r\\n2006 yılında “Üretin Gösterelim!” dedik ve yıllardır, dünyadaki İşçi Filmleri Festivallerinin ortak ağıyla ürettiklerinizi gösteriyoruz. Ana akım sinema solanları tekeline karşı, alternatif ücretsiz gösterimler yapmaya ve ana akım sinema salonlarında yer bulamamış filmleri\\r\\n\\r\\nizleyici ile buluşturmaya devam ediyoruz.\\r\\n\\r\\nGönüllü Emeğin Festivali​\\r\\n\\r\\nİşçi Filmleri Festivali için çalışan, emek veren herkes gönüllüdür. Festivalin düzenlendiği her ilde bu gönüllülerden oluşan bir festival komitesi vardır. Festival komiteleri, sinemayı seven, sinemanın bir farkındalık ve toplumsal hafıza aracı olduğunu düşünen insanlardan oluşur.\\r\\n\\r\\nBu komitelerden birinde yer almak için İşçi Filmleri Festivali’nin gönüllüsü olmak yeterlidir.\",\"_metin\":\"field_bk_metin\",\"buton_metni\":\"\",\"_buton_metni\":\"field_bk_buton_metni\",\"buton_link\":\"\",\"_buton_link\":\"field_bk_buton_link\",\"gorsel_1\":\"\",\"_gorsel_1\":\"field_bk_gorsel_1\",\"gorsel_2\":\"\",\"_gorsel_2\":\"field_bk_gorsel_2\"},\"mode\":\"edit\"} /-->','Hakkımızda','','inherit','closed','closed','','984-revision-v1','','','2026-04-26 01:59:32','2026-04-25 22:59:32','',984,'http://localhost:9090/?p=987',0,'revision','',0),(988,1,'2026-04-26 01:59:38','2026-04-25 22:59:38','<!-- wp:acf/biz-kimiz {\"name\":\"acf/biz-kimiz\",\"data\":{\"baslik\":\"Hakkımızda\",\"_basli